{
  "title": "स्ट्रक्ट लाइफटाइम",
  "group": "लाइफटाइम",
  "options": [
    {
      "text": "सफलतापूर्वक कंपाइल हो जाता है",
      "hint": "रेफरेंस वाले स्ट्रक्ट्स को लाइफटाइम एनोटेशन की आवश्यकता होती है"
    },
    {
      "text": "त्रुटि: लाइफटाइम स्पेसिफायर गायब है"
    },
    {
      "text": "त्रुटि: लाइफटाइम मिसमैच",
      "hint": "हमने अभी तक कोई लाइफटाइम निर्दिष्ट नहीं किया है"
    },
    {
      "text": "त्रुटि: अमान्य रेफरेंस",
      "hint": "रेफरेंस वैध हैं, लेकिन कुछ और गायब है"
    }
  ],
  "questionProse": [
    "क्या यह स्ट्रक्ट डिफिनिशन कंपाइल होगी? क्यों या क्यों नहीं?"
  ],
  "explanationProse": [
    "कोड फेल हो जाता है क्योंकि रेफरेंस वाले स्ट्रक्ट्स को लाइफटाइम निर्दिष्ट करना अनिवार्य है। इसे ठीक करने का तरीका यहाँ है:",
    "सामान्य पैटर्न:",
    "सर्वोत्तम प्रथाएँ:\n      1. जब डेटा को स्थायी रूप से स्टोर करना हो, तो ओन्ड टाइप्स (String) का उपयोग करें\n      2. जब स्ट्रक्ट का जीवनकाल डेटा से स्पष्ट रूप से छोटा हो, तो रेफरेंस का उपयोग करें\n      3. यदि रेफरेंस के अलग-अलग लाइफटाइम हो सकते हैं, तो एकाधिक लाइफटाइम पैरामीटर पर विचार करें\n      4. जटिल स्ट्रक्चर्स में लाइफटाइम संबंधों को स्पष्ट रूप से डॉक्यूमेंट करें"
  ]
}
